function FloatingParticle({ delay, size, left, duration }: { delay: number; size: number; left: number; duration: number }) {
  return (
    <div
      className="absolute rounded-full pointer-events-none"
      style={{
        width: size,
        height: size,
        left: `${left}%`,
        bottom: "-20px",
        background: `radial-gradient(circle, rgba(244,140,33,0.3) 0%, transparent 70%)`,
        animation: `float-up ${duration}s ease-in-out infinite`,
        animationDelay: `${delay}s`,
        opacity: 0,
      }}
    />
  );
}

